svg.script:
webMI.addEvent("id_3", "click", function(e) {
var id = "id_3";
var value = true;
webMI.display.openWindow({display:"SYSTEM.DISPLAYS.TanqueMain",extern:false,height:410,menubar:false,modal:false,movable:true,resizable:true,scrollbars:false,status:false,title:"",toolbar:false,width:700,query:webMI.query});
});



webMI.data.subscribe(webMI.query["base"] + ".level_percent", function(e) {
var id = "id_0";
var value = e.value;
webMI.gfx.setText(id, value);

});

webMI.data.subscribe(webMI.query["base"] + ".level_percent", function(e) {
var id = "id_2";
var value = e.value;
webMI.gfx.setText(id, webMI.sprintf("%.2f", value));

});
